import{c as o,Q as e,j as r,m as a}from"./chunks/framework.hhGiamYR.js";const c=JSON.parse('{"title":"假如我是教皇——马基雅维利如何走进对手的头脑","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","title":"假如我是教皇——马基雅维利如何走进对手的头脑"},"headers":[],"relativePath":"research/if-i-were-the-pope/index.md","filePath":"research/if-i-were-the-pope/index.md"}'),u={name:"research/if-i-were-the-pope/index.md"};function q(p,t,n,l,i,s){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="假如我是教皇——马基雅维利如何走进对手的头脑" tabindex="-1">假如我是教皇——马基雅维利如何走进对手的头脑 <a class="header-anchor" href="#假如我是教皇——马基雅维利如何走进对手的头脑" aria-label="Permalink to &quot;假如我是教皇——马基雅维利如何走进对手的头脑&quot;">​</a></h1><p>1513 年 6 月 20 日，被流放乡下的马基雅维利给驻罗马大使弗朗切斯科·韦托里写了一封信。信的开头很平常——几周前他写过一封信回复韦托里关于法西停战协定的讨论，之后没有回音，他听说韦托里归期推迟，就决定&quot;用这封信来拜访您&quot;。接着，他说了这样一段话：</p><blockquote><p>📖 <strong>原文</strong>：《书信集》第 213 封，致弗朗切斯科·韦托里，1513 年 6 月 20 日</p><p>&quot;我认为，明智之人永远要防患于未然，未雨绸缪以扬善抑恶，所以就让我设身处地为教皇仔细审视一下，现在究竟有什么好怕的、可采取什么补救措施。&quot;</p><p>— 全文：<a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">machiavelli/letters/1513-1527.md</a></p></blockquote><p>随后他做了这件事——<strong>假如我是教皇</strong>。接下来三页纸，他完全放弃了&quot;尼科洛·马基雅维利&quot;的视角，转而从教皇利奥十世的位置出发，推演欧洲棋盘上每一方的利益、恐惧和可能的行动：西班牙不可信赖，除非他们在意大利有更多忌惮；法国暂时不可怕，但和约比战争更危险；瑞士人的两次胜利让西班牙愈发不安；威尼斯人占有维罗纳、维琴察、帕多瓦和特雷维索，法国占有伦巴第，教皇占有自己的领土，西班牙占有那不勒斯——这样一份协定&quot;我看到极大的安全保障，因为各方对德意志人的共同恐惧会使他们和衷共济&quot;。</p><p>这是马基雅维利外交分析中最核心的方法，却也是最容易被忽略的方法。后人记住的是他的结论（&quot;被人畏惧比受人爱戴安全&quot;），而忽略了他的方法——他不是从道德出发去审判，不是从原则出发去推演，而是<strong>走进对手的头脑</strong>，从对方的利益出发去理解对方为什么那样做、接下来会怎样做。</p><h2 id="这不是换位思考" tabindex="-1">这不是换位思考 <a class="header-anchor" href="#这不是换位思考" aria-label="Permalink to &quot;这不是换位思考&quot;">​</a></h2><p>这个方法容易和&quot;共情&quot;或&quot;换位思考&quot;混淆。但它不是。马基雅维利书信集的英译本导言对此有一段极为精确的辨析：</p><blockquote><p>📖 <strong>原文</strong>：《书信集》英译本导言（引用伊丽莎白·扬—布吕尔）</p><p>&quot;马基雅维利的表达，受制于一种貌似可称为感通（empathy）的东西。然而，他的感通过程并不是&#39;和别人换位思考&#39;。伊丽莎白·扬—布吕尔言简意赅地说过这二者的区别：&#39;感通涉及把另一个人纳入你的内心，使之成为另一个人的居所，而不是把这个人消弭于无形。你在思想上孕育一个人——实际上是一个生命——一个有其历史的人，而不是孕育一个可能存在的人。于是，这个主体就生活在你的世界里，你就可以亲切地倾听他的声音。&#39;&quot;</p><p>— 全文：<a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">machiavelli/letters/1513-1527.md</a></p></blockquote><p>区别在这里：换位思考是把&quot;我&quot;放进&quot;对方的位置&quot;，带着&quot;我&quot;的价值观去想象&quot;如果是我，我会怎么做&quot;。而马基雅维利做的是相反的事——他把&quot;对方&quot;放进&quot;我的内心&quot;，让一个有其完整利益、完整历史、完整恐惧的<strong>真实的对方</strong>活在自己的思想里。他不问&quot;如果我是教皇我会怎么做&quot;，他问的是&quot;如果我是<strong>这个</strong>教皇——利奥十世，美第奇家族的乔瓦尼，年轻、富有、渴求荣耀，兄弟子侄没有寸土尺地——他会怎么做&quot;。</p><p>前者是投射。后者是模拟。投射会出错，因为你在用自己的逻辑套别人。模拟可能也会出错，但它出错的方式是你可以修正的——你只需要更好地了解对方。</p><h2 id="从急件到《君主论》-一个方法的成形" tabindex="-1">从急件到《君主论》：一个方法的成形 <a class="header-anchor" href="#从急件到《君主论》-一个方法的成形" aria-label="Permalink to &quot;从急件到《君主论》：一个方法的成形&quot;">​</a></h2><p>这个方法不是凭空产生的。它是马基雅维利十四年外交生涯的沉淀。</p><p>1502 年 12 月 31 日，33 岁的马基雅维利作为佛罗伦萨使节，在西尼加利亚见证了切萨雷·博尔贾最著名的行动——&quot;美丽的骗局&quot;。博尔贾以庆功为名，将四个叛乱首领（维泰洛佐·维泰利、奥利韦罗托·达·费尔莫、保罗·奥尔西尼和格拉维纳公爵）诱至城内，入城即捕，当晚处决。马基雅维利站在街对面，看着那扇门关上，然后是一阵使他无法下笔的寂静。他当晚给十人委员会写急件，划了七八次开头，最后只用一句话交代了结果——&quot;此后，公爵下令将维泰洛佐和奥利韦罗托处以极刑&quot;——把它放在急件的中间偏后位置，&quot;好像这只是当天发生的若干件事中的一件&quot;。</p><p>十年后，他在《君主论》第 7 章里完整地重写了这个故事。这次的叙述里没有了&quot;我站在街对面&quot;，没有了&quot;我划掉了七八次开头&quot;，没有了&quot;Venite&quot;——只剩策略本身。但如果你把两篇放一起读，你会发现同一种能力贯穿其中：在那晚的急件里，他反复划掉开头，因为他正在脑子里模拟博尔贾的决策过程，想要找到那个能解释一切的逻辑支点；在《君主论》里，他终于找到了——博尔贾&quot;已经为未来的权势奠定了牢不可破的基础&quot;，只是因为&quot;机运异常而极端的恶毒折磨&quot;才功亏一篑。</p><p>这不是&quot;揣摩上意&quot;——揣摩上意只关心对方想要什么。这是<strong>理解对方的全部处境</strong>：对方的力量从哪里来，对方怕什么失去，对方在什么条件下会改变行为。在致韦托里的信里，他对教皇利奥十世的分析不是猜测教皇&quot;在想什么&quot;，而是推演教皇的处境——美第奇家族刚重掌佛罗伦萨，教皇的兄弟子侄需要领土，瑞士人在意大利势力膨胀，西班牙感到被孤立——然后从这个处境倒推出教皇的恐惧和欲望。处境决定利益，利益决定行为。这是马基雅维利设身处地法的底层逻辑。</p><h2 id="一个方法-三种运用" tabindex="-1">一个方法，三种运用 <a class="header-anchor" href="#一个方法-三种运用" aria-label="Permalink to &quot;一个方法，三种运用&quot;">​</a></h2><p>这个方法贯穿了马基雅维利的所有重要作品——只是形式不同。</p><p>在<strong>外交急件</strong>中，它是即时工具。1500 年出使法国宫廷，他发现自己作为佛罗伦萨使节被法王和红衣主教们轻视——佛罗伦萨太小了，小到不值得认真对待。他没有愤怒，而是开始观察：法国人为什么这样做？他们的利益计算是什么？他注意到法王路易十二犯了一个错误——帮助教皇亚历山大六世扩张势力，以为这是巩固同盟。马基雅维利当场就看穿了：&quot;路易国王失去伦巴第就是因为他没有遵循那些夺取领土并希望保有领土的人所应当遵循的条件。&quot;他不是在事后分析，他是在法国宫廷里，站在那些轻视他的人面前，就已经在想通了这件事。</p><p>在《<strong>君主论</strong>》中，它是系统化的分析框架。第 7 章对切萨雷·博尔贾的分析不是赞美，也不是谴责——是一步一步重建博尔贾的决策逻辑：先依靠法国军队拿下罗马涅，再建立自己的军队替换法国人；先以残酷统一罗马涅，再派雷米罗·德·奥尔科做&quot;肮脏的事&quot;然后处决他转移民怨。马基雅维利不是博尔贾的朋友，但他能让博尔贾的逻辑完整地活在纸上——因为他在西尼加利亚那晚，已经做完了&quot;设身处地&quot;的全部工作。</p><p>在<strong>书信</strong>中，它是最自由的实验场。致韦托里的信里他扮演教皇，致圭恰迪尼的信里他扮演布道者（&quot;我会喜欢找一个将要教诲他们走向魔鬼之路的布道者&quot;），在更私密的通信里他可以随意切换角色——像一个剧作家在试演不同的剧本。别忘了，马基雅维利不只是政治分析家，他还是《曼陀罗》的作者，意大利文艺复兴最成功的喜剧。他能让舞台上的人物说出完全不像他自己的话，因为他的头脑里本来就住着不止一个人。</p><h2 id="为什么这个方法在今天仍然管用" tabindex="-1">为什么这个方法在今天仍然管用 <a class="header-anchor" href="#为什么这个方法在今天仍然管用" aria-label="Permalink to &quot;为什么这个方法在今天仍然管用&quot;">​</a></h2><p>&quot;设身处地&quot;听起来像一句陈词滥调。但如果按马基雅维利的方式去做，它是一种极其具体的操作：</p><ol><li><p><strong>不要问&quot;如果我是他，我会怎么做&quot;</strong>。问&quot;他是谁？他有什么？他怕什么？他过去做了什么？他现在的处境要求他做什么？&quot;——用对方的历史和处境去推演，而不是用自己的价值观去投射。</p></li><li><p><strong>利益比情感可靠</strong>。对方的愤怒、友善、傲慢——这些都不是可靠的判断依据。可靠的是对方在当前的权力格局中，什么东西是不能失去的，什么东西是迫切想要的。利奥十世对法国的态度，不是取决于他喜不喜欢法国，而是取决于法国驻军的位置和瑞士人的动向。</p></li><li><p><strong>模拟不是一次性的</strong>。马基雅维利在信里先推演了一个答案（&quot;我看到极大的安全保障&quot;），然后立刻自己反驳自己（&quot;但从另一方面讲，我从中又看不到任何安全保障&quot;）。设身处地的终点不是找到答案，而是看清所有的可能性——包括对方自己可能还没看清的。</p></li></ol><p>这个方法最精妙的地方在于：它不要求你喜欢你的对手，不要求你同情你的对手，甚至不要求你尊重你的对手。它只要求你——<strong>愿意看</strong>。愿意放弃&quot;他怎么可以这样&quot;的道德舒适区，进入&quot;他为什么这样&quot;的分析状态。</p><p>马基雅维利在被剥夺公职、遭受吊刑、流放乡下之后，依然能在信里平静地说&quot;让我设身处地为教皇仔细审视一下&quot;——不是因为他宽恕了美第奇家族，而是因为他知道：愤怒不会让你看清对手的下一步棋。模拟会。</p><hr><p><em>尼科洛·马基雅维利，圣卡夏诺</em></p>',27)])])}const d=o(u,[["render",q]]);export{c as __pageData,d as default};
